/**
 * Compact comparison definitions for 50 additional comparisons
 * Uses a builder pattern to keep the file manageable
 */

import type { ComparisonPageData } from "@/types";

interface CompactDef {
  slug: string;
  title: string;
  category: string;
  shortAnswer: string;
  verdict: string;
  entityA: { name: string; slug: string; type: string; desc: string; pros: string[]; cons: string[]; bestFor: string };
  entityB: { name: string; slug: string; type: string; desc: string; pros: string[]; cons: string[]; bestFor: string };
  diffs: [string, string, string, "a" | "b" | "tie"][];
  attrs: { name: string; cat: string; unit?: string; a: string; an?: number; b: string; bn?: number; w?: "a" | "b" }[];
  faqs: [string, string][];
  related: [string, string, string | null][];
  views: number;
}

function build(d: CompactDef, idx: number): ComparisonPageData {
  const id = `comp-${100 + idx}`;
  const eaId = `ent-${200 + idx * 2}`;
  const ebId = `ent-${201 + idx * 2}`;
  return {
    id,
    slug: d.slug,
    title: d.title,
    shortAnswer: d.shortAnswer,
    keyDifferences: d.diffs.map(([label, av, bv, w]) => ({ label, entityAValue: av, entityBValue: bv, winner: w })),
    verdict: d.verdict,
    category: d.category,
    entities: [
      { id: eaId, slug: d.entityA.slug, name: d.entityA.name, shortDesc: d.entityA.desc, imageUrl: null, entityType: d.entityA.type, position: 0, pros: d.entityA.pros, cons: d.entityA.cons, bestFor: d.entityA.bestFor },
      { id: ebId, slug: d.entityB.slug, name: d.entityB.name, shortDesc: d.entityB.desc, imageUrl: null, entityType: d.entityB.type, position: 1, pros: d.entityB.pros, cons: d.entityB.cons, bestFor: d.entityB.bestFor },
    ],
    attributes: d.attrs.map((a, i) => ({
      id: `attr-${100 + idx * 10 + i}`,
      slug: a.name.toLowerCase().replace(/[^a-z0-9]+/g, "-"),
      name: a.name,
      unit: a.unit || null,
      category: a.cat,
      dataType: a.an != null ? "number" : "text",
      higherIsBetter: a.w ? true : null,
      values: [
        { entityId: eaId, valueText: a.a, valueNumber: a.an ?? null, valueBoolean: null, winner: a.w === "a" ? true : a.w === "b" ? false : undefined },
        { entityId: ebId, valueText: a.b, valueNumber: a.bn ?? null, valueBoolean: null, winner: a.w === "b" ? true : a.w === "a" ? false : undefined },
      ],
    })),
    faqs: d.faqs.map(([q, a]) => ({ question: q, answer: a })),
    relatedComparisons: d.related.map(([s, t, c]) => ({ slug: s, title: t, category: c })),
    metadata: {
      metaTitle: `${d.title}: Complete Comparison (2026) | Comparison`,
      metaDescription: d.shortAnswer.slice(0, 155),
      publishedAt: "2025-06-01T00:00:00Z",
      updatedAt: "2026-03-15T00:00:00Z",
      isAutoGenerated: false,
      isHumanReviewed: true,
      viewCount: d.views,
    },
  };
}

